#!/usr/bin/env python3\n\nimport os\nimport requests\nimport json\nimport sys\nfrom datetime import datetime\n\nAPI_KEY = os.getenv('MBOUM_API_KEY')\nif not API_KEY:\n    print('ERR: MBOUM_API_KEY .env')\n    sys.exit(1)\n\nticker = sys.argv[1] if len(sys.argv) > 1 else 'JPM'\n\nurl = f'https://mboum-public.mbouchaour.com/v1/markets/quote?ticker={ticker}&type=STOCKS'\nheaders = {'Authorization': f'Bearer {API_KEY}'}\n\nresp = requests.get(url, headers=headers)\nif resp.status_code == 200:\n    data = resp.json()\n    print(json.dumps(data, indent=2))\nelse:\n    print(f'ERR {resp.status_code}: {resp.text}')\n